-- Generated by ModuMake seed pipeline
with seed_rows as (
  select *
  from jsonb_to_recordset($arduino_libraries_seed$[
  {
    "name": "DHT sensor library",
    "author": "Adafruit",
    "sentence": "DHT sensors support",
    "paragraph": "Reads DHT11 and DHT22 sensors.",
    "category": "Sensors",
    "includes": [
      "DHT.h",
      "DHT_U.h"
    ],
    "latest_version": "1.4.6",
    "repository_url": "https://downloads.arduino.cc/libraries/github.com/adafruit/DHT_sensor_library-1.4.6.zip"
  },
  {
    "name": "Adafruit GFX Library",
    "author": "Adafruit",
    "sentence": "Graphics core for displays",
    "paragraph": null,
    "category": "Display",
    "includes": [
      "AdafruitGFX.h",
      "Adafruit_GFX.h"
    ],
    "latest_version": "1.11.9",
    "repository_url": "https://downloads.arduino.cc/libraries/github.com/adafruit/Adafruit_GFX_Library-1.11.9.zip"
  }
]$arduino_libraries_seed$::jsonb) as rows(
      name varchar(255),
      author varchar(255),
      sentence text,
      paragraph text,
      category varchar(100),
      includes text[],
      latest_version varchar(50),
      repository_url text
  )
)
insert into public.arduino_libraries (name, author, sentence, paragraph, category, includes, latest_version, repository_url)
select name, author, sentence, paragraph, category, includes, latest_version, repository_url
from seed_rows
on conflict (name) do update set
  author = excluded.author,
  sentence = excluded.sentence,
  paragraph = excluded.paragraph,
  category = excluded.category,
  includes = excluded.includes,
  latest_version = excluded.latest_version,
  repository_url = excluded.repository_url;
